INSERT IGNORE INTO ingredients (id, name, `desc`, img) VALUES
  ('640c2dd963a319ea671e37aa', 'Squid', 'A type of cephalopod with a soft, cylindrical body and long tentacles, often used in seafood dishes such as calamari or grilled squid.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37aa.png'),
  ('640c2dd963a319ea671e37f5', 'Cabbage', 'A leafy green or purple vegetable that is often used in salads, coleslaw, and stir-fry dishes, and is also commonly fermented into sauerkraut.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37f5.png'),
  ('640c2dd963a319ea671e3665', 'Baking Powder', 'Baking powder is a dry chemical leavening agent, a mixture of a carbonate or bicarbonate and a weak acid. The base and acid are prevented from reacting prematurely by the inclusion of a buffer such as cornstarch. Baking powder is used to increase the volume and lighten the texture of baked goods. It works by releasing carbon dioxide gas into a batter or dough through an acid-base reaction, causing bubbles in the wet mixture to expand and thus leavening the mixture. The first single-acting baking powder was developed by Birmingham based food manufacturer Alfred Bird in England in 1843. The first double-acting baking powder was developed by Eben Norton Horsford in America in the 1860s.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3665.png'),
  ('640c2dd963a319ea671e3804', 'Smoked Haddock', 'Haddock that has been smoked over wood chips, giving it a distinctive smoky flavor', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3804.png'),
  ('640c2dd963a319ea671e382c', 'Pears', 'A sweet and juicy fruit with a soft, grainy texture and thin skin.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e382c.png'),
  ('640c2dd963a319ea671e3770', 'Spring Onions', 'Also known as scallions or green onions, these are young onions that have a mild flavor and are commonly used as a garnish or ingredient in salads, soups, stir-fries, and other dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3770.png'),
  ('640c2dd963a319ea671e36e9', 'Ginger Cordial', 'A sweet and spicy syrup made from ginger often used as a mixer in cocktails or diluted with water to make a non-alcoholic drink.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36e9.png'),
  ('640c2dd963a319ea671e3861', 'Almond Extract', 'The almond (Prunus dulcis, syn. Prunus amygdalus) is a species of tree native to Mediterranean climate regions of the Middle East, but widely cultivated elsewhere. The almond is also the name of the edible and widely cultivated seed of this tree. Within the genus Prunus, it is classified with the peach in the subgenus Amygdalus, distinguished from the other subgenera by corrugations on the shell (endocarp) surrounding the seed.
INSERT IGNORE INTO ingredients (id, name, `desc`, img) VALUES
  ('640c2dd963a319ea671e37b9', 'Clams', 'Edible bivalve mollusks with two shells, commonly used in seafood dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37b9.png'),
  ('640c2dd963a319ea671e381d', 'Treacle', 'A sweet, sticky syrup made from refined sugar, often used as a sweetener in baking and cooking', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e381d.png'),
  ('640c2dd963a319ea671e3812', 'Apricot Jam', 'A sweet spread made from apricots, often used on toast, pastries, and in baking.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3812.png'),
  ('640c2dd963a319ea671e371c', 'Massaman Curry Paste', 'Massaman curry paste is a blend of spices commonly used in Thai cuisine, particularly in dishes from the southern region of Thailand. It typically includes ingredients such as cinnamon, cardamom, cloves, and chili peppers, and is often used as a marinade or seasoning for meat, fish, or vegetables.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e371c.png'),
  ('640c2dd963a319ea671e3751', 'Red Wine', 'Alcoholic beverage made from fermented grapes or other fruits with a red color derived from the skins of dark-colored grapes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3751.png'),
  ('640c2dd963a319ea671e372e', 'Onions', 'A bulb vegetable with layers of flesh covered by a paper-like skin, used in cooking for its flavor and texture.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e372e.png'),
  ('640c2dd963a319ea671e3682', 'Cannellini Beans', 'A type of white bean that is commonly used in Italian cuisine, with a creamy texture and a mild, nutty flavor that is often used in soups, salads, and pasta dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3682.png'),
  ('640c2dd963a319ea671e3769', 'Smoked Paprika', 'Smoked paprika is a type of paprika that has been smoked over wood to give it a smoky flavor. It is commonly used in Spanish and Mexican cuisine, and can be used to add flavor to meats, stews, and soups.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3769.png'),
  ('640c2dd963a319ea671e385e', 'Ancho Chillies', 'A type of dried chili pepper that is commonly used in Mexican cuisine, with a mild to medium heat level and a fruity, smoky flavor.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e385e.png'),
  ('640c2dd963a319ea671e37bb', 'Rapeseed Oil', 'Oil extracted from the seeds of the rapeseed plant, commonly used for cooking and frying.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37bb.png'),
  ('640c2dd963a319ea671e36c2', 'Doner Meat', 'A type of meat that is typically made from lamb, chicken, or beef that has been seasoned and cooked on a vertical rotisserie. It is commonly used in Middle Eastern and Mediterranean cuisine, and is often served in sandwiches or wraps.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36c2.png'),
  ('640c2dd963a319ea671e37f9', 'Baguette', 'A long, thin loaf of French bread that has a crisp crust and a soft, chewy interior, and is often used for sandwiches and as an accompaniment to meals.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37f9.png'),
  ('640c2dd963a319ea671e3673', 'Black Treacle', 'Molasses (American English) or black treacle (British English) is a viscous product resulting from refining sugarcane or sugar beets into sugar. Molasses varies by amount of sugar, method of extraction, and age of plant. Sugarcane molasses is primarily used for sweetening and flavoring foods in the United States, Canada, and elsewhere. Molasses is a defining component of fine commercial brown sugar.
INSERT IGNORE INTO ingredients (id, name, `desc`, img) VALUES
  ('640c2dd963a319ea671e37a6', 'Fideo', 'A type of thin, spaghetti-like pasta commonly used in Mexican cuisine, often toasted before being added to soups or stews.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37a6.png'),
  ('640c2dd963a319ea671e3711', 'Lemon', 'A citrus fruit that has a sour, acidic flavor and is often used in cooking and baking to add tartness and brightness to dishes. Lemon juice and zest are commonly used in marinades, dressings, and desserts.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3711.png'),
  ('640c2dd963a319ea671e3883', 'Iceberg Lettuce', 'Iceberg is a variety of lettuce with crisp leaves that grow in a spherical head resembling cabbage. It is considered one of the sweeter lettuce varieties like romaine and butterhead. Mature iceberg lettuce grows to about one foot in diameter.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3883.png'),
  ('640c2dd963a319ea671e37ba', 'Passata', 'Tomato puree made from strained and cooked tomatoes, commonly used as a base for pasta sauces.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37ba.png'),
  ('640c2dd963a319ea671e37b0', 'Duck', 'A domesticated bird that is commonly used for meat. Duck meat is known for its rich, gamey flavor and is often roasted or grilled.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37b0.png'),
  ('640c2dd963a319ea671e365f', 'Avocado', 'The avocado, a tree with probable origin in South Central Mexico, is classified as a member of the flowering plant family Lauraceae. The fruit of the plant, also called an avocado (or avocado pear or alligator pear), is botanically a large berry containing a single large seed.
INSERT IGNORE INTO ingredients (id, name, `desc`, img) VALUES
  ('640c2dd963a319ea671e367f', 'Cacao', 'The dried and fermented seed of the cocoa tree, which is processed into cocoa powder and chocolate products, and used in baking, confectionery, and other food products.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e367f.png'),
  ('640c2dd963a319ea671e36c4', 'Dried Oregano', 'A dried herb that is commonly used in Mediterranean and Mexican cuisine. It has a pungent, slightly bitter flavor that pairs well with tomato-based sauces, meats, and vegetables.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36c4.png'),
  ('640c2dd963a319ea671e3736', 'Parmesan Cheese', 'See Parmesan.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3736.png'),
  ('640c2dd963a319ea671e36ee', 'Granulated Sugar', 'A common sweetener made from sugar cane or sugar beet that has been refined and granulated.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36ee.png'),
  ('640c2dd963a319ea671e36ef', 'Grape Tomatoes', 'A small, bite-sized tomato variety with a sweet and slightly tangy flavor commonly used in salads and as a snack.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36ef.png'),
  ('640c2dd963a319ea671e3703', 'Italian Seasoning', 'A blend of dried herbs and spices commonly used in Italian cuisine, including basil, oregano, rosemary, thyme, and garlic.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3703.png'),
  ('640c2dd963a319ea671e3897', 'Ciabatta', 'Ciabatta is an Italian white bread made from wheat flour, water, salt, yeast and olive oil, created in 1982 by a baker in Adria, province of Rovigo, Veneto, Italy, in response to the popularity of French baguettes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3897.png'),
  ('640c2dd963a319ea671e3755', 'Rice Stick Noodles', 'Thick, flat noodles made from rice flour and water and commonly used in Southeast Asian cuisine, such as in pad see ew or char kway teow.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3755.png'),
  ('640c2dd963a319ea671e365b', 'Chicken', 'The chicken is a type of domesticated fowl, a subspecies of the red junglefowl (Gallus gallus). It is one of the most common and widespread domestic animals, with a total population of more than 19 billion as of 2011. There are more chickens in the world than any other bird or domesticated fowl. Humans keep chickens primarily as a source of food (consuming both their meat and eggs) and, less commonly, as pets. Originally raised for cockfighting or for special ceremonies, chickens were not kept for food until the Hellenistic period (4th–2nd centuries BC).
INSERT IGNORE INTO ingredients (id, name, `desc`, img) VALUES
  ('640c2dd963a319ea671e3873', 'Ground Pork', 'Ground meat, called mince or minced meat outside of North America (i.e. in U.K. and Commonwealth countries), and keema or qeema (Hindustani: क़ीमा (Devanagari), قیمہ (Nastaleeq), (pronounced [ˈqiːmaː])) in the Indian subcontinent, is meat finely chopped by a meat grinder or a chopping knife. A common type of ground meat is ground beef, but many other types of meats are prepared in a similar fashion, including pork, lamb, and poultry. In the Indian subcontinent, both mutton and goat meat are also minced to produce keema.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3873.png'),
  ('640c2dd963a319ea671e377b', 'Thai Red Curry Paste', 'A spicy blend of herbs and spices, including red chilies, lemongrass, and ginger, used as a base for Thai red curry.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e377b.png'),
  ('640c2dd963a319ea671e379b', 'Pretzels', 'A type of baked snack food made from dough that is shaped into a distinctive knot or twisted shape, then boiled in water and baked. Often served as a snack with dips or as a side dish with beer.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e379b.png'),
  ('640c2dd963a319ea671e371b', 'Marjoram', 'Marjoram is a herb that is commonly used as a seasoning for meat, fish, and vegetable dishes. It has a slightly sweet and floral flavor, and is often used in Mediterranean and Middle Eastern cuisines.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e371b.png'),
  ('640c2dd963a319ea671e37a3', 'Clotted Cream', 'A thick, rich cream made by heating unpasteurized cow\'s milk until a layer of cream forms on the surface and is then skimmed off.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37a3.png'),
  ('640c2dd963a319ea671e37ee', 'Lentils', 'Lentils are a type of legume that are commonly used in soups, stews, salads, and other culinary applications. They have a mild, nutty flavor and are high in protein, fiber, and other nutrients.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37ee.png'),
  ('640c2dd963a319ea671e37e3', 'Peanut Brittle', 'Peanut brittle is a type of confection made with sugar, corn syrup, peanuts, and butter. It is cooked to a hard, brittle consistency and can be broken into pieces for snacking.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37e3.png'),
  ('640c2dd963a319ea671e3756', 'Rice Vermicelli', 'Thin, translucent noodles made from rice flour and water and commonly used in Southeast Asian cuisine, such as in bun or mi xao don.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3756.png'),
  ('640c2dd963a319ea671e3864', 'Black Beans', 'The black turtle bean is a small, shiny variety of the common bean (Phaseolus vulgaris) especially popular in Latin American cuisine, though it can also be found in the Cajun and Creole cuisines of south Louisiana. Like most common beans, it is native to the Americas, but has been introduced around the world. It is also used in East Indian cooking, Punjabi cuisine, and in Maharashtrian cuisine, it is known as Kala Ghevada. It is used interchangeably with vigna mungo (black gram) in countries such as the United States. The black turtle bean is often simply called the black bean (frijoles negros, zaragoza, judía negra, poroto negro, or caraota o habichuela negra in Spanish; and feijão preto in Portuguese), although this terminology can cause confusion with other black beans.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3864.png'),
  ('640c2dd963a319ea671e36ac', 'Colby Jack Cheese', 'A semi-hard cheese made from cow\'s milk, with a mild flavor and creamy texture. It is a combination of Colby and Monterey Jack cheese.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36ac.png'),
  ('640c2dd963a319ea671e36a5', 'Cinnamon', 'A sweet and aromatic spice commonly used in baking, made from the inner bark of cinnamon trees.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36a5.png'),
  ('640c2dd963a319ea671e36f8', 'Ground Ginger', 'Ground ginger is a spice made from dried ginger root that has been ground into a powder. It is commonly used in baking and Asian cuisine to add a warm, spicy flavor to dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36f8.png'),
  ('640c2dd963a319ea671e37e1', 'Peanut Cookies', 'Cookies that are made with peanuts or peanut butter. They have a nutty and sweet flavor.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37e1.png'),
  ('640c2dd963a319ea671e36d3', 'Feta', 'A salty, crumbly cheese typically made from sheep\'s milk or a blend of sheep\'s and goat\'s milk. Often used in Mediterranean cuisine in salads, pastries, and as a topping for grilled meats.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36d3.png'),
  ('640c2dd963a319ea671e37f6', 'Shiitake Mushrooms', 'A type of edible mushroom that is commonly used in East Asian cuisine for its savory, meaty flavor, and is often dried and rehydrated before use.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37f6.png'),
  ('640c2dd963a319ea671e37b1', 'Duck Legs', 'The legs of a duck, which are prized for their flavorful and tender meat. Duck legs are often slow-cooked or confit, which involves cooking them in their own fat.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37b1.png'),
  ('640c2dd963a319ea671e3820', 'Egg', 'A reproductive cell laid by female animals, often used in baking and cooking as a binding agent or to add texture and flavor', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3820.png'),
  ('640c2dd963a319ea671e3713', 'Lemon Zest', 'Lemon zest is the outermost layer of the lemon peel, which is rich in essential oils and has a strong, citrusy aroma and flavor. It is commonly used as a flavoring agent in cooking, baking, and cocktails.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3713.png'),
  ('640c2dd963a319ea671e3669', 'Basmati Rice', 'Basmati is a variety of long, slender-grained aromatic rice which is traditionally from the Indian subcontinent. As of 2018-19, India exported to over 90% of the overseas basmati rice market, while Pakistan accounted for the remainder, according to the Indian state-run Agricultural and Processed Food Products Export Development Authority  and the Pakistan government-run Economic Survey of Pakistan. Many countries use domestically grown basmati rice crops; however, basmati is geographically exclusive to select districts of India, Pakistan, Nepal and Bangladesh.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3669.png'),
  ('640c2dd963a319ea671e37cb', 'Rosemary', 'An herb with a pine-like fragrance and strong, earthy flavor, commonly used in Mediterranean and Italian cuisine to add flavor to dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37cb.png'),
  ('640c2dd963a319ea671e376d', 'Soya Milk', 'A plant-based milk made from soybeans that is a popular alternative to dairy milk. It is high in protein, vitamins, and minerals, and is commonly used as a milk substitute in cooking and baking.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e376d.png'),
  ('640c2dd963a319ea671e36d1', 'Fennel Seeds', 'Small, aromatic seeds from the fennel plant with a sweet, licorice-like flavor. Often used in Indian and Middle Eastern cuisine as a spice and digestive aid.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36d1.png'),
  ('640c2dd963a319ea671e3896', 'Sardines', '"Sardine" and "pilchard" are common names that refer to various small, oily forage fish in the herring family Clupeidae. The term "sardine" was first used in English during the early 15th century and may come from the Mediterranean island of Sardinia, around which sardines were once abundant.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3896.png'),
  ('640c2dd963a319ea671e3888', 'Boiling Water', 'Water is an inorganic, transparent, tasteless, odorless, and nearly colorless chemical substance, which is the main constituent of Earth\'s hydrosphere and the fluids of most living organisms. It is vital for all known forms of life, even though it provides no calories or organic nutrients. Its chemical formula is H2O, meaning that each of its molecules contains one oxygen and two hydrogen atoms, connected by covalent bonds. Water is the name of the liquid state of H2O at standard ambient temperature and pressure. It forms precipitation in the form of rain and aerosols in the form of fog. Clouds are formed from suspended droplets of water and ice, its solid state. When finely divided, crystalline ice may precipitate in the form of snow. The gaseous state of water is steam or water vapor. Water moves continually through the water cycle of evaporation, transpiration (evapotranspiration), condensation, precipitation, and runoff, usually reaching the sea.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3888.png'),
  ('640c2dd963a319ea671e3670', 'Bicarbonate Of Soda', 'Sodium bicarbonate, commonly known as baking soda, is a chemical compound with the formula NaHCO3. It is a salt composed of a sodium cation (Na+) and a bicarbonate anion (HCO3−). Sodium bicarbonate is a white solid that is crystalline, but often appears as a fine powder. It has a slightly salty, alkaline taste resembling that of washing soda (sodium carbonate). The natural mineral form is nahcolite. It is a component of the mineral natron and is found dissolved in many mineral springs.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3670.png'),
  ('640c2dd963a319ea671e36fc', 'Heavy Cream', 'Heavy cream, also known as whipping cream, is a type of dairy product that has a high fat content. It is commonly used in baking, cooking, and as a topping for desserts like fruit and ice cream.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36fc.png'),
  ('640c2dd963a319ea671e37a2', 'Fettuccine', 'A type of pasta that is long and flat, wider than linguine but narrower than tagliatelle.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37a2.png'),
  ('640c2dd963a319ea671e3801', 'Lamb Kidney', 'An organ meat that is commonly used in traditional British dishes such as steak and kidney pie, and is known for its distinct flavor and texture.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3801.png'),
  ('640c2dd963a319ea671e3870', 'Bread Rolls', 'A roll is a small, usually round or oblong individual loaf of bread served as a meal accompaniment (eaten plain or with butter) A roll can be served and eaten whole or cut transversely and dressed with filling between the two halves. Rolls are also commonly used to make sandwiches similar to those produced using slices of bread. They are found in most cuisines all over the world. In the Deipnosophistae, the author Athenaeus (c. 170 – c. 230) describes some of the bread, cakes, and pastries available in the Classical world. Among the breads mentioned are griddle cakes, honey-and-oil bread, mushroom-shaped loaves covered in poppy seeds, and the military specialty of rolls baked on a spit.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3870.png'),
  ('640c2dd963a319ea671e36a9', 'Cocoa', 'A powder made from roasted and ground cocoa beans, commonly used in baking to add chocolate flavor to desserts.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36a9.png'),
  ('640c2dd963a319ea671e3758', 'Rocket', 'Also known as arugula or rucola, it is a leafy green vegetable with a distinctive peppery flavor commonly used in salads and sandwiches.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3758.png'),
  ('640c2dd963a319ea671e3708', 'Khus Khus', 'Also known as poppy seeds, khus khus are tiny seeds that have a nutty flavor and a crunchy texture. They are commonly used as a topping for breads and pastries or in Indian cuisine.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3708.png'),
  ('640c2dd963a319ea671e388f', 'Herring', 'Herring are forage fish, mostly belonging to the family Clupeidae. Herring often move in large schools around fishing banks and near the coast, found particularly in shallow, temperate waters of the North Pacific and North Atlantic Oceans, including the Baltic Sea, as well as off the west coast of South America.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e388f.png'),
  ('640c2dd963a319ea671e37e7', 'Courgettes', 'Courgettes, also known as zucchini, are a type of summer squash with a mild, slightly sweet flavor. They are commonly used in salads, soups, and other culinary applications.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37e7.png'),
  ('640c2dd963a319ea671e36c7', 'Egg Rolls', '', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36c7.png'),
  ('640c2dd963a319ea671e37b6', 'Sugar Snap Peas', 'A type of pea that has edible pods. Sugar snap peas are sweet and crunchy and can be eaten raw or cooked.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37b6.png'),
  ('640c2dd963a319ea671e36c5', 'Dry White Wine', 'A type of white wine that is not sweet, with most of the grape sugar having been fermented into alcohol. It is often used in cooking to deglaze pans, add flavor to sauces, and to tenderize meats.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36c5.png'),
  ('640c2dd963a319ea671e371d', 'Medjool Dates', 'A type of large, sweet, and chewy date fruit with a caramel-like flavor, commonly used as a natural sweetener in desserts or as a snack.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e371d.png'),
  ('640c2dd963a319ea671e3895', 'Beetroot', 'The beetroot is the taproot portion of a beet plant, usually known in Canada and the USA as beets while the vegetable is referred to as beetroot in British English, and also known as the table beet, garden beet, red beet, dinner beet or golden beet.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3895.png'),
  ('640c2dd963a319ea671e376c', 'Soy Sauce', 'A sauce made from soybeans, roasted grain, water, and salt. It is commonly used as a condiment and flavoring in Asian cuisine, and is often used to season stir-fries, marinades, and dipping sauces.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e376c.png'),
  ('640c2dd963a319ea671e36a1', 'Chopped Tomatoes', 'Tomatoes that have been chopped into small pieces, commonly used as a base for sauces, soups, and stews.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36a1.png'),
  ('640c2dd963a319ea671e3710', 'Leek', 'A type of allium vegetable that is related to onions and garlic. Leeks have a mild, sweet flavor and can be eaten raw or cooked in a variety of dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3710.png'),
  ('640c2dd963a319ea671e367c', 'Brown Rice', 'A type of rice that has been minimally processed to remove the outermost layer of the grain, resulting in a nutty flavor and a chewy texture that is often used in pilafs, salads, and other dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e367c.png'),
  ('640c2dd963a319ea671e3721', 'Miniature Marshmallows', 'Small, soft, and pillowy confectionery items that are typically made from sugar, water, and gelatin, and are often used as a topping for hot chocolate, desserts, and cakes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3721.png'),
  ('640c2dd963a319ea671e37e4', 'Peaches', 'Peaches are a juicy fruit with fuzzy skin and a sweet flavor. They are commonly eaten fresh or used in desserts, jams, and other culinary applications.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37e4.png'),
  ('640c2dd963a319ea671e3745', 'Potato Starch', 'A fine, white powder that is extracted from potatoes and is used as a thickening agent in cooking and baking.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3745.png'),
  ('640c2dd963a319ea671e371f', 'Milk', 'A white liquid produced by mammals as food for their young, commonly used as a drink or ingredient in cooking and baking.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e371f.png'),
  ('640c2dd963a319ea671e369c', 'Chilli Powder', 'A spice blend made from ground dried chili peppers and other spices, commonly used in Mexican, Indian, and Thai cuisine to add heat and flavor to dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e369c.png'),
  ('640c2dd963a319ea671e37dc', 'Dark Chocolate Chips', 'Small, bite-sized pieces of dark chocolate often used in baking cookies, brownies, or muffins, or as a topping for ice cream or yogurt bowls.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37dc.png'),
  ('640c2dd963a319ea671e3843', 'Red Snapper', 'The northern red snapper (Lutjanus campechanus) is a species of snapper native to the western Atlantic Ocean including the Gulf of Mexico, where it inhabits environments associated with reefs. This species is commercially important and is also sought-after as a game fish.
INSERT IGNORE INTO ingredients (id, name, `desc`, img) VALUES
  ('640c2dd963a319ea671e378e', 'Vinegar', 'A sour liquid made from fermented alcohol, used as a condiment and preservative.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e378e.png'),
  ('640c2dd963a319ea671e3681', 'Canned Tomatoes', 'Tomatoes that have been preserved in a can or jar, typically with added salt and sometimes other seasonings, and used in a variety of recipes such as soups, stews, sauces, and chili.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3681.png'),
  ('640c2dd963a319ea671e3878', 'Chicken Stock Concentrate', 'Stock, sometimes called bone broth, is a savory cooking liquid that forms the basis of many dishes, particularly soups, stews and sauces. Making stock involves simmering animal bones or meat, seafood, or vegetables in water or wine, often for an extended period of time. Mirepoix or other aromatics may be added for more flavor.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3878.png'),
  ('640c2dd963a319ea671e37ab', 'Fish Stock', 'A flavorful broth made by simmering fish bones, vegetables, and aromatics in water, often used as a base for soups, stews, and sauces.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37ab.png'),
  ('640c2dd963a319ea671e37f4', 'Udon Noodles', 'A type of thick, wheat-based noodle that is commonly used in Japanese cuisine, particularly in soups and stir-fry dishes.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37f4.png'),
  ('640c2dd963a319ea671e36b3', 'Cornstarch', 'A fine, powdery starch made from corn kernels that is commonly used as a thickening agent in sauces, soups, and gravies.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e36b3.png'),
  ('640c2dd963a319ea671e3889', 'Pickle Juice', 'Pickling is the process of preserving or extending the shelf life of food by either anaerobic fermentation in brine or immersion in vinegar. In East Asia, vinaigrette is also used as a pickling medium. The pickling procedure typically affects the food\'s texture, taste and flavor.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e3889.png'),
  ('640c2dd963a319ea671e37f3', 'Tortillas', 'Thin, flatbreads made from corn or wheat flour that are commonly used in Mexican cuisine for dishes like tacos, burritos, and quesadillas.', 'https://ftp.goit.study/img/so-yummy/ingredients/640c2dd963a319ea671e37f3.png'),
  ('640c2dd963a319ea671e384a', 'Scallions', 'Scallions (green onion, spring onion and salad onion) are vegetables of various Allium onion species. Scallions have a milder taste than most onions. Their close relatives include the garlic, shallot, leek, chive, and Chinese onion.
