INSERT IGNORE INTO recipes (title, category, owner_id, area, calories, instructions, description, thumb, time) VALUES ('Fettuccine Alfredo', 'Pasta', 1, 'Italian', NULL, 'Cook pasta according to package instructions in a large pot of boiling water and salt. Add heavy cream and butter to a large skillet over medium heat until the cream bubbles and the butter melts. Whisk in parmesan and add seasoning (salt and black pepper). Let the sauce thicken slightly and then add the pasta and toss until coated in sauce. Garnish with parsley, and it\'s ready.', 'Fettuccine Alfredo is a classic Italian pasta dish made with fettuccine pasta, butter, cream, and Parmesan cheese. It\'s a simple yet decadent dish that\'s perfect for a special occasion or a cozy dinner at home.', 'https://ftp.goit.study/img/so-yummy/preview/Fettuccine%20Alfredo.jpg', '20');
